insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '[안내] 202X년 상반기 시스템 정기 점검 안내', '<p>안녕하세요. [회사/서비스명] 운영팀입니다.</p><p>항상 저희 서비스를 이용해 주셔서 감사합니다.</p><p>보다 안정적인 서비스 제공을 위해 아래와 같이 시스템 점검이 진행될 예정입니다.</p><p>점검 일시: 202X년 X월 X일(요일) 00:00 ~ 00:00 (약 0시간)</p><p>영향 범위: 홈페이지 접속 및 서비스 일시 중단</p><p>참고 사항: 작업 상황에 따라 점검 시간이 단축되거나 연장될 수 있습니다.</p><p>이용에 불편을 드려 죄송하며, 더 나은 서비스로 보답하겠습니다.</p><p>감사합니다.&nbsp;</p>', '', null, '', null, 0, 0, 0, '20260316203213', 'N', 'N', 'system', '20260316203213', 'system', '20260316203213');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '[공지] 추석 연휴 배송 및 고객센터 운영 안내', '<p>안녕하세요. [쇼핑몰명]입니다.</p><p>추석 연휴 배송 물량 증가로 인해 배송 일정을 안내드립니다.</p><ul><li>최종 발송일: X월 X일(요일) 오후 0시 이전 주문 건</li><li>업무 중단 기간: X월 X일(요일) ~ X월 X일(요일)</li><li>정상 업무 개시: X월 X일(요일)부터 순차적 배송 및 상담</li></ul>', '', null, '', null, 0, 0, 0, '20260316203246', 'N', 'N', 'system', '20260316203246', 'system', '20260316203246');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '모임/동창회 공지 예시 (메시지형)', '<p>친구들 안녕! 어느덧 하반기가 되었네.</p><p>오랜만에 얼굴도 보고 회포도 풀 겸 모임을 가지려 해.</p><ul><li>일시: 11/15(토) 오후 6시</li><li>장소: 강남역 00식당 (지도 링크)</li><li>회비: 3만원 (계좌번호: OO은행 XXX-XXXX-XXX)&nbsp;</li></ul><p><b>참석 여부는 11/10까지 꼬옥~ 회신 부탁해!&nbsp;</b></p><p><br></p>', '', null, '', null, 0, 0, 0, '20260316203922', 'Y', 'N', 'system', '20260316203324', 'system', '20260316203922');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '먹거리매장 시범사업 참여매장 현황', '<p>먹거리매장 시범사업 참여매장 현황</p><p>자세한 사항은 첨부파일을 참고해주시기 바랍니다.</p>', '', null, '', null, 0, 0, 0, '20260316203537', 'N', 'N', 'system', '20260316203537', 'system', '20260316203537');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '사무실 휴무 안내', '<p>오는 3월 25일(수)은 내부 워크숍으로 인해 전 직원 재택근무를 실시합니다.</p><p>방문 및 전화 상담이 제한되오니 양해 부탁드립니다</p>', '', null, '', null, 0, 0, 0, '20260316203603', 'N', 'N', 'system', '20260316203603', 'system', '20260316203603');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '정기 점검 안내', '<p>시스템 안정화를 위한 서버 점검이 4월 2일(목) 00:00~04:00에 진행됩니다.&nbsp;</p><p>해당 시간 동안 서비스 이용이 제한될 수 있습니다.</p>', '', null, '', null, 0, 0, 0, '20260316203655', 'N', 'N', 'system', '20260316203655', 'system', '20260316203655');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '신입사원 환영회 공지', '<p>3월 20일(금) 오후 6시, 본사 대회의실에서 신입사원 환영회를 개최합니다.&nbsp;</p><p>전 직원 참석 부탁드립니다.</p>', '', null, '', null, 0, 0, 0, '20260316203709', 'N', 'N', 'system', '20260316203709', 'system', '20260316203709');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '보안 교육 실시 안내', '<p>개인정보 보호 및 보안 강화를 위한 정기 교육이 3월 18일(수) 오후 2시에 진행됩니다.&nbsp;</p><p>필수 참석 대상자는 인사팀에서 별도 안내드립니다.</p>', '', null, '', null, 0, 0, 0, '20260316203904', 'Y', 'N', 'system', '20260316203722', 'system', '20260316203904');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '사내 카페 운영시간 변경', '<p>4월부터 사내 카페 운영시간이 오전 8시~오후 6시로 변경됩니다.&nbsp;</p><p>이용에 참고 부탁드립니다.</p>', '', null, '', null, 0, 0, 0, '20260316203737', 'N', 'N', 'system', '20260316203737', 'system', '20260316203737');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '연말 정산 서류 제출 안내', '<p>3월 31일까지 연말 정산 관련 서류를 인사팀에 제출해 주시기 바랍니다.&nbsp;</p><p>기한 내 미제출 시 불이익이 있을 수 있습니다.</p>', '', null, '', null, 0, 0, 0, '20260316203753', 'N', 'N', 'system', '20260316203753', 'system', '20260316203753');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '사내 동호회 모집 공지', '<p>2026년 상반기 사내 동호회 신규 회원을 모집합니다.&nbsp;</p><p>관심 있는 직원은 3월 22일까지 신청서를 제출해 주세요.</p>', '', null, '', null, 0, 0, 0, '20260316203807', 'N', 'N', 'system', '20260316203807', 'system', '20260316203807');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '회의실 예약 시스템 변경 안내', '<p>4월부터 새로운 회의실 예약 시스템이 도입됩니다.&nbsp;</p><p>사용 방법은 사내 포털 공지사항을 참고해 주세요.</p>', '', null, '', null, 0, 0, 0, '20260316203855', 'Y', 'N', 'system', '20260316203823', 'system', '20260316203855');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '사내 방역 실시 안내', '<p>직원들의 안전을 위해 3월 19일(목) 오후 7시에 사무실 전체 방역을 실시합니다.&nbsp;</p><p>퇴근 시 개인 물품을 정리해 주시기 바랍니다.</p>', '', null, '', null, 0, 0, 0, '20260316203834', 'N', 'N', 'system', '20260316203834', 'system', '20260316203834');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('notice', null, '사내 공모전 개최 안내', '<p>창의적인 아이디어 발굴을 위한 사내 공모전을 개최합니다.&nbsp;</p><p>접수 기간은 3월 15일~4월 10일이며, 우수 아이디어는 실제 프로젝트에 반영됩니다.</p>', '', null, '', null, 0, 0, 0, '20260316203849', 'N', 'N', 'system', '20260316203849', 'system', '20260316203849');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '회원가입은 어떻게 하나요?', '<p>홈페이지 상단의 ‘회원가입’ 버튼을 클릭하시면 됩니다.</p><p>이메일과 비밀번호를 입력하고 인증 절차를 거치면 가입이 완료됩니다.</p><p>가입 후에는 프로필을 설정할 수 있습니다.</p><p>SNS 계정으로도 간편하게 가입 가능합니다.</p>', '', null, '', null, 0, 0, 0, '20260316204134', 'N', 'N', 'system', '20260316204051', 'system', '20260316204134');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '비밀번호를 잊어버렸어요. 어떻게 해야 하나요?', '<p>- 비밀번호를 잊어버렸어요. 어떻게 해야 하나요?</p><p>로그인 화면에서 ‘비밀번호 찾기’를 클릭하세요.</p><p>가입 시 등록한 이메일을 입력하면 재설정 링크가 발송됩니다.</p><p>해당 링크를 통해 새로운 비밀번호를 설정할 수 있습니다.</p><p>보안을 위해 주기적으로 비밀번호를 변경하는 것을 권장합니다.</p>', '', null, '', null, 0, 0, 0, '20260316204104', 'N', 'N', 'system', '20260316204104', 'system', '20260316204104');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '배송 기간은 얼마나 걸리나요?', '<p>- 배송 기간은 얼마나 걸리나요?</p><p>일반적으로 주문 후 2~3일 내에 배송됩니다.</p><p>지역에 따라 배송 기간은 달라질 수 있습니다.</p><p>명절이나 연휴에는 배송이 지연될 수 있습니다.</p><p>배송 조회는 마이페이지에서 가능합니다.</p>', '', null, '', null, 0, 0, 0, '20260316204142', 'N', 'N', 'system', '20260316204114', 'system', '20260316204142');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '환불은 어떻게 진행되나요?', '<p>- 환불은 어떻게 진행되나요?</p><p>상품 수령 후 7일 이내에 환불 신청이 가능합니다.</p><p>단, 사용 흔적이나 훼손이 있는 경우 환불이 제한됩니다.</p><p>환불 신청은 고객센터 또는 마이페이지에서 가능합니다.</p><p>환불 완료까지는 영업일 기준 3~5일 정도 소요됩니다.</p>', '', null, '', null, 0, 0, 0, '20260316204150', 'N', 'N', 'system', '20260316204124', 'system', '20260316204150');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '고객센터 운영 시간은 언제인가요?', '<p>-&nbsp;고객센터 운영 시간은 언제인가요?</p><p>평일 오전 9시부터 오후 6시까지 운영됩니다.</p><p>점심시간은 12시~1시로 전화 연결이 어려울 수 있습니다.</p><p>토요일과 공휴일은 휴무입니다.</p>', '', null, '', null, 0, 0, 0, '20260316204208', 'N', 'N', 'system', '20260316204208', 'system', '20260316204208');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '포인트는 어떻게 적립되나요?', '<p>- 포인트는 어떻게 적립되나요?</p><p>상품 구매 시 결제 금액의 일정 비율이 포인트로 적립됩니다.</p><p>이벤트 참여 시 추가 포인트를 받을 수 있습니다.</p><p>적립된 포인트는 다음 구매 시 현금처럼 사용 가능합니다.</p><p>포인트 유효기간은 적립일로부터 1년입니다.</p>', '', null, '', null, 0, 0, 0, '20260316204223', 'N', 'N', 'system', '20260316204223', 'system', '20260316204223');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '해외 배송도 가능한가요?', '<p>- 해외 배송도 가능한가요?</p><p>일부 국가에 한해 해외 배송을 지원합니다.</p><p>배송 가능 국가 목록은 홈페이지에서 확인할 수 있습니다.</p><p>해외 배송은 국내보다 기간이 길어질 수 있습니다.</p><p>추가 배송비가 발생할 수 있으니 참고 바랍니다.</p>', '', null, '', null, 0, 0, 0, '20260316204235', 'N', 'N', 'system', '20260316204235', 'system', '20260316204235');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '상품 교환은 어떻게 하나요?', '<p>- 상품 교환은 어떻게 하나요?</p><p>교환은 상품 수령 후 7일 이내에 신청 가능합니다.</p><p>동일 상품의 사이즈나 색상 교환만 가능합니다.</p><p>교환 신청은 고객센터를 통해 접수해야 합니다.</p><p>교환 완료까지는 영업일 기준 5~7일 정도 소요됩니다.</p>', '', null, '', null, 0, 0, 0, '20260316204246', 'N', 'N', 'system', '20260316204246', 'system', '20260316204246');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '이벤트 참여 방법을 알려주세요.', '<p>- 이벤트 참여 방법을 알려주세요.</p><p>이벤트는 홈페이지 공지사항에서 확인할 수 있습니다.</p><p>참여 조건과 방법은 이벤트별로 다릅니다.</p><p>응모 후 당첨자는 개별 연락을 통해 안내됩니다.</p><p>이벤트 참여 시 개인정보 제공에 동의해야 합니다.</p>', '', null, '', null, 0, 0, 0, '20260316204256', 'N', 'N', 'system', '20260316204256', 'system', '20260316204256');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '뉴스레터 구독은 어떻게 하나요?', '<p>- 뉴스레터 구독은 어떻게 하나요?</p><p>홈페이지 하단의 ‘뉴스레터 구독’ 버튼을 클릭하세요.</p><p>이메일 주소를 입력하면 구독 신청이 완료됩니다.</p><p>매주 최신 소식과 이벤트 정보를 받아볼 수 있습니다.</p><p>구독 해지는 언제든지 이메일 하단 링크에서 가능합니다</p>', '', null, '', null, 0, 0, 0, '20260316204307', 'N', 'N', 'system', '20260316204307', 'system', '20260316204307');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '회원 탈퇴는 어떻게 하나요?', '<p>&nbsp; &nbsp;마이페이지에서 ‘회원 탈퇴’ 메뉴를 선택하세요.&nbsp;&nbsp;</p><p>&nbsp; &nbsp;탈퇴 시 모든 포인트와 쿠폰은 소멸됩니다.&nbsp;&nbsp;</p><p>&nbsp; &nbsp;재가입은 언제든지 가능하지만 기존 데이터는 복구되지 않습니다.&nbsp;&nbsp;</p><p>&nbsp; &nbsp;탈퇴 후에도 일정 기간 동안 거래 기록은 보관됩니다.&nbsp;&nbsp;</p>', '', null, '', null, 0, 0, 0, '20260316204407', 'N', 'N', 'system', '20260316204407', 'system', '20260316204407');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '쿠폰은 어떻게 사용하나요?', '<p>결제 화면에서 ‘쿠폰 적용’ 버튼을 클릭하세요.&nbsp;&nbsp;</p><p>보유 중인 쿠폰 목록이 자동으로 표시됩니다.&nbsp;&nbsp;</p><p>원하는 쿠폰을 선택하면 결제 금액에 반영됩니다.&nbsp;&nbsp;</p><p>일부 상품은 쿠폰 적용이 제한될 수 있습니다.&nbsp;&nbsp;</p>', '', null, '', null, 0, 0, 0, '20260316204423', 'N', 'N', 'system', '20260316204423', 'system', '20260316204423');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '상품이 품절되면 어떻게 되나요?', '<p>품절 상품은 구매가 불가능합니다.&nbsp;&nbsp;</p><p>재입고 알림 신청을 통해 입고 시 안내를 받을 수 있습니다.&nbsp;&nbsp;</p><p>인기 상품은 빠르게 품절될 수 있으니 서둘러 구매하세요.&nbsp;&nbsp;</p><p>대체 상품을 추천받을 수도 있습니다.&nbsp;&nbsp;</p>', '', null, '', null, 0, 0, 0, '20260316204433', 'N', 'N', 'system', '20260316204433', 'system', '20260316204433');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '배송 주소를 변경하고 싶어요.', '<p>주문 완료 후에는 주소 변경이 제한됩니다.&nbsp;&nbsp;</p><p>단, 배송 준비 전 단계라면 고객센터를 통해 변경 가능합니다.&nbsp;&nbsp;</p><p>이미 배송이 시작된 경우에는 변경이 불가능합니다.&nbsp;&nbsp;</p><p>주소 입력 시 오타가 없는지 꼭 확인해 주세요.&nbsp;&nbsp;</p>', '', null, '', null, 0, 0, 0, '20260316204444', 'N', 'N', 'system', '20260316204444', 'system', '20260316204444');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '상품 리뷰는 어떻게 작성하나요?', '<p>상품 수령 후 마이페이지에서 리뷰 작성이 가능합니다.&nbsp;&nbsp;</p><p>사진과 함께 리뷰를 작성하면 추가 포인트가 지급됩니다.&nbsp;&nbsp;</p><p>리뷰는 다른 고객들에게 큰 도움이 됩니다.&nbsp;&nbsp;</p><p>부적절한 리뷰는 관리자에 의해 삭제될 수 있습니다.&nbsp;&nbsp;</p>', '', null, '', null, 0, 0, 0, '20260316204456', 'N', 'N', 'system', '20260316204456', 'system', '20260316204456');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '결제 수단은 어떤 것이 있나요?', '<p>신용카드, 체크카드, 계좌이체, 간편결제를 지원합니다.&nbsp;&nbsp;</p><p>일부 이벤트 상품은 특정 결제 수단만 가능할 수 있습니다.&nbsp;&nbsp;</p><p>결제 오류 발생 시 고객센터로 문의해 주세요.&nbsp;&nbsp;</p><p>결제 내역은 마이페이지에서 확인 가능합니다.&nbsp;&nbsp;</p>', '', null, '', null, 0, 0, 0, '20260316204506', 'N', 'N', 'system', '20260316204506', 'system', '20260316204506');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '상품 보증 기간은 어떻게 되나요?', '<p>7. **상품 보증 기간은 어떻게 되나요?**&nbsp;&nbsp;</p><p>상품별로 보증 기간은 상이합니다.&nbsp;&nbsp;</p><p>일반적으로 전자제품은 1년 보증이 제공됩니다.&nbsp;&nbsp;</p><p>보증 기간 내에는 무상 수리 또는 교환이 가능합니다.&nbsp;&nbsp;</p><p>보증서와 영수증을 반드시 보관해 주세요.&nbsp;&nbsp;</p>', '', null, '', null, 0, 0, 0, '20260316204604', 'Y', 'N', 'system', '20260316204520', 'system', '20260316204604');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '알림 설정은 어떻게 하나요?', '<p>8. **알림 설정은 어떻게 하나요?**&nbsp;&nbsp;</p><p>마이페이지에서 ‘알림 설정’ 메뉴를 확인하세요.&nbsp;&nbsp;</p><p>이메일, 문자, 앱 푸시 알림을 개별적으로 설정할 수 있습니다.&nbsp;&nbsp;</p><p>원하지 않는 알림은 언제든지 해제 가능합니다.&nbsp;&nbsp;</p><p>중요한 공지사항은 기본적으로 발송됩니다.&nbsp;&nbsp;</p>', '', null, '', null, 0, 0, 0, '20260316204529', 'N', 'N', 'system', '20260316204529', 'system', '20260316204529');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '상품이 파손되어 도착했어요', '<p>상품이 파손되어 도착했어요</p><p>즉시 고객센터로 사진과 함께 신고해 주세요.&nbsp;&nbsp;</p><p>파손 확인 후 교환 또는 환불이 진행됩니다.&nbsp;&nbsp;</p><p>배송 중 발생한 문제는 업체에서 책임집니다.&nbsp;&nbsp;</p><p>빠른 처리를 위해 수령 후 바로 확인해 주세요.&nbsp;&nbsp;</p>', '', null, '', null, 0, 0, 0, '20260316204541', 'N', 'N', 'system', '20260316204541', 'system', '20260316204541');
insert into mng_board (board_id, category, title, contents, main_image_id, url_link, pdf_file_id, youtube_link, comment_cnt, heart_cnt, hit_cnt, reg_date, notice_yn, del_yn, ins_id, ins_date, upd_id, upd_date) values ('faq', null, '정기 구독 서비스는 어떻게 해지하나요?', '<p>마이페이지에서 ‘구독 관리’ 메뉴를 선택하세요.&nbsp;&nbsp;</p><p>해지 신청 후 다음 결제일부터 자동으로 중단됩니다.&nbsp;&nbsp;</p><p>이미 결제된 금액은 환불되지 않습니다.&nbsp;&nbsp;</p><p>해지 후에도 언제든지 다시 구독할 수 있습니다.&nbsp;&nbsp;</p>', '', null, '', null, 0, 0, 0, '20260316204552', 'N', 'N', 'system', '20260316204552', 'system', '20260316204552');
